from flask import Flask, request, make_response, url_for, redirect
import jwt
import base64
import hashlib
import hmac
import time

app = Flask(__name__)
SECRET_KEY = 'your_secret_key'
ALGORITHM = 'HS256'

REGISTRATION_DATA = {
    "flexible_oauth": {
        "client_id": "123456",
        "redirect_uris": ["https://example.com", "https://staging.example.com", "https://prod.example.com"],
        "expires_in": 86400
    }
}

def generate_token(client_id, expires_in):
    payload = {
        'exp': time() + expires_in,
        'iat': time(),
        'client_id': client_id,
    }

    encoded_payload = jwt.encode(payload, SECRET_KEY, ALGORITHM).decode('utf-8')
    return encoded_payload

def verify_token(token):
    try:
        decoded = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        return decoded['client_id']
    except jwt.ExpiredSignatureError:
        pass
    except jwt.InvalidTokenError:
        pass
    return None

def hash_input(s):
    h = hashlib.sha256()
    h.update(str.encode(s))
    return h.hexdigest()

@app.route('/authorize')
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')

    if not REGISTRATION_DATA.get(client_id):
        return "Invalid client_id", 400

    for registered_uri in REGISTRATION_DATA[client_id]["redirect_uris"]:
        if redirect_uri.startswith(registered_uri):
            state = hash_input(f"{client_id}_{redirect_uri}_{int(time().time())}")
            access_token = generate_token(client_id, REGISTRATION_DATA[client_id]["expires_in"])
            token_param = f'access_token={access_token}&state={state}'
            return redirect(redirect_uri + '?' + token_param)

    return "Invalid redirect_uri", 400

@app.route('/token')
def token():
    client_id = request.args.get('client_id')
    state = request.args.get('state')

    if not REGISTRATION_DATA.get(client_id):
        return "Invalid client_id", 401

    received_state = hash_input(f"{client_id}_{request.headers['Authorization'].split()[1]}_{int(time().time())}")

    if state != received_state:
        return "Invalid state", 403

    verified_token = verify_token(request.headers['Authorization'].split()[1])

    if not verified_token or verified_token != client_id:
        return "Invalid token", 401

    response = make_response("Token verified!")
    response.data = bytes()
    return response